SELECT e.id, e.job_id AS jobId, e.fire_log_id AS fireLogId, e.alarm_type AS alarmType, e.alarm_content AS alarmContent, e.notify_status AS notifyStatus, e.trigger_time AS triggerTime, ( SELECT GROUP_CONCAT(DISTINCT r.channel ORDER BY r.channel SEPARATOR ',') FROM job_alarm_notify_record r WHERE r.alarm_event_id = e.id ) AS notifyChannels FROM job_alarm_event e WHERE e.job_id = #{jobId}
AND e.alarm_type = #{request.alarmType}
AND e.notify_status = #{request.notifyStatus}
ORDER BY e.trigger_time DESC
LIMIT #{request.size} OFFSET ${(request.current - 1) * request.size}

SELECT COUNT(*)
FROM job_alarm_event e
WHERE e.job_id = #{jobId}

    AND e.alarm_type = #{request.alarmType}


    AND e.notify_status = #{request.notifyStatus}

SELECT e.id, e.job_id AS jobId, e.fire_log_id AS fireLogId, e.alarm_type AS alarmType, e.alarm_content AS alarmContent, e.notify_status AS notifyStatus, e.trigger_time AS triggerTime, ( SELECT GROUP_CONCAT(DISTINCT r.channel ORDER BY r.channel SEPARATOR ',') FROM job_alarm_notify_record r WHERE r.alarm_event_id = e.id ) AS notifyChannels FROM job_alarm_event e WHERE 1 = 1
AND e.job_id = #{request.jobId}
AND e.alarm_type = #{request.alarmType}
AND e.notify_status = #{request.notifyStatus}
ORDER BY e.trigger_time DESC
LIMIT #{request.size} OFFSET ${(request.current - 1) * request.size}

SELECT COUNT(*)
FROM job_alarm_event e
WHERE 1 = 1

    AND e.job_id = #{request.jobId}


    AND e.alarm_type = #{request.alarmType}


    AND e.notify_status = #{request.notifyStatus}

SELECT id, job_id, fire_log_id, alarm_type, alarm_content, notify_status, trigger_time, create_time, update_time
FROM job_alarm_event
WHERE id = #{id}

